/**
 * Get training program by problem id
 * @param {string} problemId
 * @returns {object|null}
 */
export function getTrainingProgram(problemId) {
  return TRAINING_PROGRAMS[problemId] || null;
}

/**
 * Get all problem ids
 * @returns {string[]}
 */
export function getAllProblemIds() {
  return Object.keys(TRAINING_PROGRAMS);
}